"use strict";


module.exports = function (isbn) {
  /*isbn 十位转 13位    odd jishu  even 偶数*/
  var odd = 0,
      even = 0,
      newNum;
  isbn = isbn.toString();
  if (isbn.length > 10) return isbn;
  var str = isbn.slice(0, 9);
  str = '978' + str;
  for (var i = 0; i < str.length; i++) {
    /*因为从零开始的 所以奇偶交换*/
    if (i % 2 === 0) {
      odd += Number(str[i]);
    } else {
      even += Number(str[i]);
    }
    newNum = 10 - (odd + even * 3) % 10;
  }
  str += newNum.toString();
  return str;
};

